mapper.select:
SELECT roster_id, tenant_id, community_name, building_id, building_name, unit_name, room_id, room_name, build_area FROM c_property_roster WHERE status = 'ACTIVE'
AND tenant_id = #{tenantId}
ORDER BY community_name, building_id, unit_name, room_name

SELECT building_id
FROM c_property_roster
WHERE tenant_id = #{tenantId}
  AND building_name = #{buildingName}
ORDER BY roster_id ASC
LIMIT 1

SELECT room_id
FROM c_property_roster
WHERE tenant_id = #{tenantId}
  AND building_name = #{buildingName}
  AND unit_name = #{unitName}
  AND room_name = #{roomName}
LIMIT 1

SELECT claim_id, account_id, uid, tenant_id, roster_id, building_id, building_name, unit_name, room_id, room_name, applicant_real_name, applicant_phone, roster_owner_name, roster_owner_phone, match_result, claim_status, is_joint_ownership, is_voting_delegate, proof_type, proof_material_json::text AS proof_material_json, reject_reason_code, reject_reason, reviewed_by, reviewed_at, bound_opid, create_time FROM c_owner_property_claim WHERE 1 = 1
AND tenant_id = #{tenantId}
AND claim_status = #{status}
ORDER BY create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM c_owner_property_claim
WHERE 1 = 1

    AND tenant_id = #{tenantId}


    AND claim_status = #{status}

mapper.update:
UPDATE c_owner_property
SET is_voting_delegate = 0,
    update_time = CURRENT_TIMESTAMP
WHERE tenant_id = #{tenantId}
  AND room_id = #{roomId}
  AND uid != #{uid}
  AND account_status = 1

mapper.select:
SELECT opid
FROM c_owner_property
WHERE uid = #{uid}
  AND tenant_id = #{tenantId}
  AND room_id = #{roomId}
LIMIT 1
